@app.route('/authorize', methods=['GET'])
def authorize():
    client_id = request.args.get('client_id')
    redirect_uri = request.args.get('redirect_uri')
    response_type = request.args.get('response_type')
    scope = request.args.get('scope', '').split(' ')
    state = request.args.get('state')

    if not client_id or not redirect_uri or not response_type:
        return jsonify({"error": "invalid_request", "error_description": "Missing required parameters"}), 400

    if response_type != 'code':
        return jsonify({"error": "unsupported_response_type", "error_description": "Only 'code' is supported"}), 400

    client = CLIENTS.get(client_id)
    if not client:
        return jsonify({"error": "unauthorized_client", "error_description": "Client not registered"}), 401

    if not validate_redirect_uri(client_id, redirect_uri):
        return jsonify({"error": "invalid_redirect_uri", "error_description": "Redirect URI mismatch"}), 400

    # Check requested scopes against registered scopes
    allowed_scopes = client.get('scope', [])
    for s in scope:
        if s and s not in allowed_scopes:
            return jsonify({"error": "invalid_scope", "error_description": f"Scope '{s}' not allowed for this client"}), 400

    session['oauth_request'] = {
        'client_id': client_id,
        'redirect_uri': redirect_uri,
        'scope': scope,
        'state': state,
    }

    # In a real application, you'd show a login/consent screen here.
    # For simplicity, we'll auto-login a dummy user.
    # If the user is not logged in, redirect to a login page first.
    if 'user_id' not in session:
        return render_template('login.html', client_id=client_id, scopes=scope, redirect_uri=redirect_uri, state=state)

    return render_template('consent.html', client_id=client_id, scopes=scope, user_id=session['user_id'])


@app.route('/login', methods=['POST'])
def login():
    username = request.form.get('username')
    password = request.form.get('password')

    oauth_request = session.get('oauth_request')
    if not oauth_request:
        return jsonify({"error": "invalid_request", "error_description": "No pending OAuth request"}), 400

    if username in USERS and USERS[username]['password'] == password:
        session['user_id'] = username
        return redirect(url_for('authorize')) # Redirect back to authorize to process consent
    else:
        return render_template('login.html', error="Invalid username or password",
                               client_id=oauth_request['client_id'],
                               scopes=oauth_request['scope'],
                               redirect_uri=oauth_request['redirect_uri'],
                               state=oauth_request['state'])


@app.route('/consent', methods=['POST'])
def consent():
    oauth_request = session.pop('oauth_request', None)
    if not oauth_request:
        return jsonify({"error": "invalid_request", "error_description": "No pending OAuth request"}), 400

    user_id = session.get('user_id')
    if not user_id:
        return jsonify({"error": "access_denied", "error_description": "User not logged in"}), 401

    # In a real app, you'd check if the user granted consent for the requested scopes.
    # For simplicity, we assume consent is granted.
    consent_granted = request.form.get('consent_granted')
    if consent_granted != 'yes':
        # User denied consent
        error_params = {
            'error': 'access_denied',
            'error_description': 'User denied access',
        }
        if oauth_request['state']:
            error_params['state'] = oauth_request['state']
        return redirect(f"{oauth_request['redirect_uri']}?{urlencode(error_params)}")

    auth_code = generate_token()
    AUTHORIZATION_CODES[auth_code] = {
        'client_id': oauth_request['client_id'],
        'redirect_uri': oauth_request['redirect_uri'],
        'scope': oauth_request['scope'],
        'user_id': user_id,
        'expires_at': datetime.utcnow() + timedelta(minutes=5)
    }

    params = {
        'code': auth_code,
    }
    if oauth_request['state']:
        params['state'] = oauth_request['state']

    # Construct the redirect URI with the authorization code
    parsed_uri = urlparse(oauth_request['redirect_uri'])
    query_params = parse_qs(parsed_uri.query)
    query_params.update(params)
    new_query = urlencode(query_params, doseq=True)
    redirect_to = urlunparse(parsed_uri._replace(query=new_query))

    return redirect(redirect_to)


@app.route('/token', methods=['POST'])
def token():
    grant_type = request.form.get('grant_type')
    client_id = request.form.get('client_id')
    client_secret = request.form.get('client_secret')

    if not grant_type or not client_id or not client_secret:
        return jsonify({"error": "invalid_request", "error_description": "Missing required parameters"}), 400

    client = CLIENTS.get(client_id)
    if not client or client['client_secret'] != client_secret:
        return jsonify({"error": "invalid_client", "error_description": "Invalid client credentials"}), 401

    if grant_type == 'authorization_code':
        code = request.form.get('code')
        redirect_uri = request.form.get('redirect_uri')

        if not code or not redirect_uri:
            return jsonify({"error": "invalid_request", "error_description": "Missing code or redirect_uri for authorization_code grant"}), 400

        auth_code_data = AUTHORIZATION_CODES.pop(code, None) # Codes are single-use
        if not auth_code_data:
            return jsonify({"error": "invalid_grant", "error_description": "Invalid or expired authorization code"}), 400

        if auth_code_data['client_id'] != client_id:
            return jsonify({"error": "invalid_grant", "error_description": "Authorization code not issued to this client"}), 400

        if auth_code_data['redirect_uri'] != redirect_uri:
            # The redirect_uri must exactly match the one used in the /authorize request
            return jsonify({"error": "invalid_grant", "error_description": "Redirect URI mismatch"}), 400

        if auth_code_data['expires_at'] < datetime.utcnow():
            return jsonify({"error": "invalid_grant", "error_description": "Authorization code expired"}), 400

        access_token = generate_token()
        expires_in = 3600 # 1 hour
        ACCESS_TOKENS[access_token] = {
            'client_id': client_id,
            'user_id': auth_code_data['user_id'],
            'scope': auth_code_data['scope'],
            'expires_at': datetime.utcnow() + timedelta(seconds=expires_in)
        }

        return jsonify({
            'access_token': access_token,
            'token_type': 'Bearer',
            'expires_in': expires_in,
            'scope': ' '.join(auth_code_data['scope']),
        })

    # Add other grant types (e.g., client_credentials, refresh_token) as needed
    return jsonify({"error": "unsupported_grant_type", "error_description": "Grant type not supported"}), 400


@app.route('/userinfo', methods=['GET'])
def userinfo():
    auth_header = request.headers.get('Authorization')
    if not auth_header or not auth_header.startswith('Bearer '):
        return jsonify({"error": "invalid_token", "error_description": "Missing or malformed Authorization header"}), 401

    access_token = auth_header.split(' ')[1]
    token_data = ACCESS_TOKENS.get(access_token)

    if not token_data or token_data['expires_at'] < datetime.utcnow():
        return jsonify({"error": "invalid_token", "error_description": "Invalid or expired access token"}), 401

    user_id = token_data['user_id']
    requested_scope = token_data['scope']

    user_info = get_user_info(user_id, requested_scope)

    if not user_info:
        return jsonify({"error": "insufficient_scope", "error_description": "User information not available for requested scope"}), 403

    return jsonify(user_info)

